      STOF(ISTOF + 49) = RT_23
      STOF(ISTOF + 54) = RT_28
      STOF(ISTOF + 59) = Pitch_max
      STOF(ISTOF + 60) = Pitch_min


!---------------------------------------
! Close Model Data read
!---------------------------------------

      IF ( TIMEZERO ) CALL EMTDC_CLOSEFILE
      RETURN
      END

